            if (temp <= 65536) {

                for (i = partition_count + c_p_c - 1; i >= partition_count; i--) {

                    temp2 = (((uint64_t)temp) * inverse_class) >> 32;



                    if (i < vr->ptns_to_read)

                        vr->classifs[p + i] = temp - temp2 * vr->classifications;

                    temp = temp2;

                }

            } else {

                for (i = partition_count + c_p_c - 1; i >= partition_count; i--) {

                    temp2 = temp / vr->classifications;



                    if (i < vr->ptns_to_read)

                        vr->classifs[p + i] = temp - temp2 * vr->classifications;

                    temp = temp2;

                }

            }

        }

        p += vr->ptns_to_read;

    }

    return 0;

}

