    int icont, ichan;

    int rearm = 0;

    static int running = 0;



    if (running) {

        rearm = 1;

        goto out;

    } else {

        running = 1;

    }



    d = dma_controllers;



    for (icont = 0; icont < 2; icont++, d++) {

        for (ichan = 0; ichan < 4; ichan++) {

            int mask;



            mask = 1 << ichan;



            if ((0 == (d->mask & mask)) && (0 != (d->status & (mask << 4)))) {

