    if(huff.max_bits == 0)

        huff.max_bits = 1;



    /* allocate space for codes - it is exactly ceil(nodes / 2) entries */

    huff.max_num = (huff.nodes + 1) >> 1;

    huff.nums = av_mallocz(huff.max_num * sizeof(int));

    huff.bits = av_mallocz(huff.max_num * sizeof(uint32_t));

