        int j;

        int Y1 = 1 << 18;

        int Y2 = 1 << 18;



        for (j = 0; j < lumFilterSize; j++) {

            Y1 += lumSrc[j][i]   * lumFilter[j];

            Y2 += lumSrc[j][i+1] * lumFilter[j];

