        Y1 >>= 19;

        Y2 >>= 19;

        if ((Y1 | Y2) & 0x100) {

            Y1 = av_clip_uint8(Y1);

            Y2 = av_clip_uint8(Y2);

        }

        acc += acc + g[Y1 + d128[(i + 0) & 7]];

        acc += acc + g[Y2 + d128[(i + 1) & 7]];

        if ((i & 7) == 6) {

            output_pixel(*dest++, acc);

        }

    }

