        }

    }



    for (i = 0; i < 0x10000; i++) {

        blk_schid.sch_no = i;

        r = stsch_err(blk_schid, &schib);

        if (r == 3) {

            break;

        }

        if (schib.pmcw.dnv) {

            if (!check_devno || (schib.pmcw.dev == dev_no)) {

                if (virtio_is_blk(blk_schid)) {

                    found = true;

                    break;

                }

            }

        }

    }



    if (!found) {

        virtio_panic("No virtio-blk device found!\n");

    }



    virtio_setup_block(blk_schid);

