static int vnc_auth_sasl_check_access(VncState *vs)

{

    const void *val;

    int err;

    int allow;



    err = sasl_getprop(vs->sasl.conn, SASL_USERNAME, &val);

    if (err != SASL_OK) {

        VNC_DEBUG("cannot query SASL username on connection %d (%s), denying access\n",

                  err, sasl_errstring(err, NULL, NULL));

