    shift = scale_factor_modshift[scale_factor];

    mod = shift & 3;

    shift >>= 2;

    /* XXX: store the result directly */

    val = (2 * (mant - (steps >> 1))) * scale_factor_mult2[steps >> 2][mod];

    return (val + (1 << (shift - 1))) >> shift;

}

