                       || !compare(s, &(*next_point)->pkt, pkt)))

                next_point = &(*next_point)->next;

            if (*next_point)

                goto next_non_null;

        } else {

            next_point = &(s->packet_buffer_end->next);

        }

    }

    av_assert1(!*next_point);



    s->packet_buffer_end = this_pktl;

