static int kvm_get_fpu(CPUState *env)

{

    struct kvm_fpu fpu;

    int i, ret;



    ret = kvm_vcpu_ioctl(env, KVM_GET_FPU, &fpu);

    if (ret < 0)

        return ret;



    env->fpstt = (fpu.fsw >> 11) & 7;

    env->fpus = fpu.fsw;

