static int process_ea_header(AVFormatContext *s) {

    uint32_t blockid, size = 0;

    EaDemuxContext *ea = s->priv_data;

    ByteIOContext *pb = &s->pb;



    blockid = get_le32(pb);

    if (blockid == MVhd_TAG) {

