        process_video_header_vp6(s);

        url_fskip(pb, size-32);

        blockid = get_le32(pb);

    }

    if (blockid != SCHl_TAG)

        return 0;

    size += get_le32(pb);

    blockid = get_le32(pb);

    if (blockid == GSTR_TAG) {

        url_fskip(pb, 4);

