    int vdevice_off, node_off, ret;

    char *dt_name;



    vdevice_off = fdt_path_offset(fdt, "/vdevice");

    if (vdevice_off < 0) {

        return vdevice_off;

    }



    dt_name = vio_format_dev_name(dev);

    if (!dt_name) {

        return -ENOMEM;

    }



    node_off = fdt_add_subnode(fdt, vdevice_off, dt_name);

    free(dt_name);

    if (node_off < 0) {

        return node_off;

    }



    ret = fdt_setprop_cell(fdt, node_off, "reg", dev->reg);

    if (ret < 0) {

        return ret;

