        major = avio_r8(s->pb);

        minor = avio_r8(s->pb);

        avio_skip(s->pb, 4); // size of file

        size = read16(s);

        if (size < 14)

            return AVERROR_INVALIDDATA;



        avio_skip(s->pb, size - 14);

        pos = avio_tell(s->pb);

        if (avio_rl32(s->pb) != MKTAG('H','E','A','D'))

            return AVERROR_INVALIDDATA;

