        uint32_t info_offset = 0;

        uint16_t section_count, header_size, i;



        header_size = read16(s); // 6



        avio_skip(s->pb, 4); // Unknown constant 0x00030000

        avio_skip(s->pb, 4); // size of file

        section_count = read16(s);

        avio_skip(s->pb, 2); // padding

